What does this program print?

```cpp
#include <iostream>
#include <vector>
struct Book { std::string title; };
struct Shelf {
    std::vector<Book*> books;
    void add(Book* b) { books.push_back(b); }
    ~Shelf() { std::cout << "Shelf gone\n"; }
};
int main() {
    Book b1{"C++ Primer"};
    Book b2{"Effective C++"};
    {
        Shelf s;
        s.add(&b1);
        s.add(&b2);
    }
    std::cout << b1.title << "\n";
}
```

This program should print "Alice" but crashes or produces undefined behavior. What is the bug?

```cpp
#include <iostream>
#include <string>
struct Student { std::string name; };
struct Group {
    Student* member;
};
Group makeGroup() {
    Student s{"Alice"};
    Group g;
    g.member = &s;
    return g;  // s destroyed here
}
int main() {
    Group g = makeGroup();
    std::cout << g.member->name << "\n";
}
```
